UPDATE public.app_prompts
SET content = content || E'\n\n=== ПРАВИЛО SUGGESTED_FIX ===\nПоле suggested_fix — это ВСЕГДА готовый текст, который встанет в статью ВМЕСТО quote, от лица автора, тем же стилем и тоном. НИКОГДА не пиши в suggested_fix инструкцию редактору ("удалить", "убрать", "переформулировать", "атрибутировать", "заменить", "оставить", "уточнить", "запросить", "добавить", "сократить"). Если готовую замену дать невозможно — suggested_fix = null, а рекомендацию редактору помести в поле verdict.\nПример правильного fix для безымянного эксперта: quote «"...цитата..." — отмечают специалисты» → suggested_fix «По моему опыту работы с объектами в этом районе, ...цитата...». Пример НЕПРАВИЛЬНОГО fix: «Атрибутировать конкретному эксперту или удалить» — это инструкция, ей место в verdict, а suggested_fix должен быть null.'
WHERE key = 'fact_critic'
  AND content NOT LIKE '%ПРАВИЛО SUGGESTED_FIX%';